//开始时间: 2025/8/28 10:30
#include <bits/stdc++.h>
#define x first
#define y second
using namespace std;
typedef pair<long long,int> PLI;

const int N=1e5+10;

int n,m,a[N],l[N],stk[N],top,op[N],hh,tt;
long long s[N],f[N],t[N<<2];
bool inq[N];
priority_queue< PLI,vector<PLI>,greater<PLI> > q;

void modify(int cur,int l,int r,int x){
	if(l==r){
		t[cur]=f[l];
		return;
	}
	int mid=l+r>>1;
	if(x<=mid)
		modify(cur*2,l,mid,x);
	else
		modify(cur*2+1,mid+1,r,x);
	t[cur]=min(t[cur*2],t[cur*2+1]);
} 

long long query(int cur,int l,int r,int x,int y){
	if(x<=l && r<=y)
		return t[cur];
	int mid=l+r>>1;
	long long res=1e18;
	if(x<=mid)
		res=min(res,query(cur*2,l,mid,x,y));
	if(y>mid)
		res=min(res,query(cur*2+1,mid+1,r,x,y));
	return res;
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++){
        scanf("%d",&a[i]);
        if(a[i]>m){
            printf("-1");
            return 0;
        }
        s[i]=s[i-1]+a[i];
    }
    for(int i=n;i;i--){
    	while(top && a[stk[top]]<a[i])
    		l[stk[top]]=i,top--;
    	stk[++top]=i;
	}
	while(top)
		l[stk[top]]=0,top--;
    f[0]=0;
    hh=0,tt=-1;
    for(int i=1,j=0;i<=n;i++){
    	while(s[i]-s[j]>m)
    		j++;
    	while(hh<=tt && op[hh]<=j)
    		inq[op[hh]]=0,hh++;
    	while(hh<=tt && a[op[tt]]<=a[i])
			inq[op[tt]]=0,tt--;
		op[++tt]=i;
		q.push(make_pair(query(1,0,n,max(j,l[i]),i-1)+a[i],i));
		if(hh<tt)
			q.push(make_pair(query(1,0,n,max(j,l[op[hh]]),op[hh]-1)+a[op[hh]],op[hh]));
		inq[i]=1;
		while(q.size() && (!inq[q.top().y] || q.top().x!=query(1,0,n,max(j,l[q.top().y]),q.top().y-1)+a[q.top().y]))
			q.pop();
		f[i]=q.top().x;
		modify(1,0,n,i);
		//printf("%d %d\n",f[i],q.top().y);
	}
	printf("%lld",f[n]);
    return 0;
}
